mapper.select:
select 
from t_r_service_registry
where `type` = #{type}
  and host = #{host}
  and port = #{port}
limit 1

mapper.update:
update t_r_service_registry
set heartbeat = #{heartbeat},
    task_count = #{taskCount},
    status = 'ONLINE'
where `type` = #{type}
  and host = #{host}
  and port = #{port}

update t_r_service_registry
set status = 'OFFLINE',
    heartbeat = #{offlineAt}
where id = #{id}
  and status = 'ONLINE'
  and heartbeat  <  #{threshold}

update t_r_service_registry
set status = 'OFFLINE',
    heartbeat = #{heartbeat}
where `type` = #{type}
  and host = #{host}
  and port = #{port}
  and status = 'ONLINE'

mapper.delete:
delete from t_r_service_registry
where status = 'OFFLINE'
  and heartbeat  <  #{threshold}
